COMMENT ON TABLE connected_plant_uat.gold_io_reporting.gold_batch_lineage IS
  'Governed batch traceability edge list — T2 of the Final Trace migration (ADR 016). One row per directed traceability edge: PARENT_* → CHILD_* with LINK_TYPE classifying the relationship. Five legs: PRODUCTION (CHVW × MSEG GR), STO/BATCH/MATERIAL_TRANSFER (CHVW receiving side), VENDOR_RECEIPT (MSEG PO receipt), DELIVERY (MSEG outbound issue), ADJUSTMENT_IN / ADJUSTMENT_OUT (MSEG stock adjustments). Lifecycle-gated: SOLD / DIVESTED_ON_SAP endpoint plants excluded (ADR 016 §2). Column names are the verbatim legacy contract (deliberate snake_case exception, ADR 016 §3). Security: capability-tier GRANT via trace_security_{env}.sql; no RLS row filter on the MV (T3 search views carry the per-user predicate). Grain: one edge per (parent_material × parent_batch × parent_plant × child_material × child_batch × child_plant × link_type × process_order_id × material_document_number). Deterministic base (no current_date / current_timestamp). NOTE: first materialisation requires a full gold pipeline run; parity check vs legacy link-type counts is the orchestrator''s post-rollout step.';
ALTER TABLE connected_plant_uat.gold_io_reporting.gold_batch_lineage SET TAGS (
  'layer' = 'gold',
  'product_area' = 'ioreporting'
);
-- (no column comments yet for gold_batch_lineage — populate in backfill phase)

